CREATE TABLE IF NOT EXISTS public.reminders (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), task_id uuid NOT NULL REFERENCES public.tasks(id) ON DELETE CASCADE, type text NOT NULL CHECK (type IN ('absolute', 'relative')), trigger_at timestamptz NOT NULL, notification_sent boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.reminders ENABLE ROW LEVEL SECURITY; CREATE POLICY view_own_reminders ON public.reminders FOR SELECT USING (EXISTS (SELECT 1 FROM public.tasks t WHERE t.id = reminders.task_id AND t.user_id = auth.uid())); CREATE POLICY insert_own_reminders ON public.reminders FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM public.tasks t WHERE t.id = reminders.task_id AND t.user_id = auth.uid())); CREATE POLICY update_own_reminders ON public.reminders FOR UPDATE USING (EXISTS (SELECT 1 FROM public.tasks t WHERE t.id = reminders.task_id AND t.user_id = auth.uid())); CREATE POLICY delete_own_reminders ON public.reminders FOR DELETE USING (EXISTS (SELECT 1 FROM public.tasks t WHERE t.id = reminders.task_id AND t.user_id = auth.uid())); CREATE INDEX IF NOT EXISTS idx_reminders_trigger ON public.reminders(trigger_at) WHERE notification_sent = false; CREATE TABLE IF NOT EXISTS public.comments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), task_id uuid NOT NULL REFERENCES public.tasks(id) ON DELETE CASCADE, user_id uuid NOT NULL, content text NOT NULL, created_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.comments ENABLE ROW LEVEL SECURITY; CREATE POLICY view_own_comments ON public.comments FOR SELECT USING (auth.uid() = user_id); CREATE POLICY insert_own_comments ON public.comments FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY update_own_comments ON public.comments FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY delete_own_comments ON public.comments FOR DELETE USING (auth.uid() = user_id);